## 2. The C++ / pybind11 binding (single file)

Save the following as **`blocksci_bindings.cpp`**.  It can be compiled with a standard `setup.py` (shown at the end).

```cpp
// blocksci_bindings.cpp ----------------------------------------------------
//  Build with:  python -m pip install .   (see the tiny setup.py below)
//  Requires:   pybind11 >= 2.6, a C++17 compiler, and the real BlockSci headers.
//  For the purpose of this example we mock the BlockSci iterator.
// -------------------------------------------------------------------------

#include <pybind11/pybind11.h>
#include <pybind11/chrono.h>    // for std::chrono <-> datetime conversion
#include <pybind11/stl.h>       // for automatic conversion of std::vector<T>
#include <chrono>
#include <string>
#include <vector>
#include <thread>
#include <mutex>
#include <atomic>
#include <iostream>

namespace py = pybind11;

// -------------------------------------------------------------------------
//  Mock of the real BlockSci block representation.
//  In production you would #include <blocksci/...> and use its types.
// -------------------------------------------------------------------------
struct NativeBlock {
    uint32_t height;
    std::string hash;                // hex string
    std::chrono::seconds timestamp; // seconds since epoch (UTC)
    uint32_t tx_count;
    uint32_t size_bytes;
    // ... many more fields exist in the real library
};

// -------------------------------------------------------------------------
//  Lightweight Python‑visible wrapper (no heavy copying).
// -------------------------------------------------------------------------
class Block {
public:
    // Construct from a native block – we copy only cheap fields.
    explicit Block(const NativeBlock& nb)
        : height_(nb.height),
          hash_(std::move(nb.hash)),
          timestamp_(std::chrono::system_clock::time_point(nb.timestamp)),
          tx_count_(nb.tx_count),
          size_(nb.size_bytes) {}

    // ---------------------------------------------------------------------
    //  Read‑only accessors – exposed as properties in Python.
    // ---------------------------------------------------------------------
    uint32_t height() const { return height_; }
    const std::string& hash() const { return hash_; }
    std::chrono::system_clock::time_point timestamp() const { return timestamp_; }
    uint32_t tx_count() const { return tx_count_; }
    uint32_t size() const { return size_; }

private:
    uint32_t height_;
    std::string hash_;
    std::chrono::system_clock::time_point timestamp_;
    uint32_t tx_count_;
    uint32_t size_;
};

// -------------------------------------------------------------------------
//  Mock of the native BlockSci iterator.  Replace this with the real iterator.
// -------------------------------------------------------------------------
class NativeBlockIterator {
public:
    NativeBlockIterator(uint64_t total_blocks = 800'000'000ULL)
        : total_(total_blocks), cur_(0) {}

    bool has_next() const { return cur_ < total_; }

    // Returns a *copy* of the next block (cheap fields only).
    NativeBlock next() {
        // In a real implementation you would fetch the block from disk/database.
        NativeBlock nb;
        nb.height = static_cast<uint32_t>(cur_);
        nb.hash = "deadbeef" + std::to_string(cur_); // fake hash
        nb.timestamp = std::chrono::seconds(1231006505 + cur_ * 600); // genesis + 10‑min steps
        nb.tx_count = 200 + (cur_ % 1000); // fake tx count
        nb.size_bytes = 1'000 + (cur_ % 500);
        ++cur_;
        return nb;
    }

private:
    uint64_t total_;
    uint64_t cur_;
};

// -------------------------------------------------------------------------
//  Core walking routine – the hot path.
// -------------------------------------------------------------------------
template <typename Callback>
void walk_blocks_impl(Callback&& cb,
                      uint64_t total_blocks,
                      size_t batch,
                      bool parallel) {
    // -----------------------------------------------------------------
    //  The iterator itself lives *outside* the GIL; we release it for the
    //  whole duration of the walk.  The only time we acquire the GIL is
    //  when we need to invoke the Python callback.
    // -----------------------------------------------------------------
    NativeBlockIterator it(total_blocks);

    // -----------------------------------------------------------------
    //  Helper that calls the Python callback under the GIL.
    // -----------------------------------------------------------------
    auto call_python = [&](std::vector<Block>& batch_vec) {
        py::gil_scoped_acquire gil;          // acquire for the duration of the call
        if (batch == 1) {
            // Single‑block mode – unpack the one element.
            cb(batch_vec[0]);
        } else {
            // Batch mode – pass a Python list.
            cb(py::cast(batch_vec));
        }
    };

    if (!parallel) {
        // --------------------------- single‑threaded ---------------------------
        std::vector<Block> batch_buf;
        batch_buf.reserve(batch);
        while (it.has_next()) {
            NativeBlock nb = it.next();
            batch_buf.emplace_back(nb);
            if (batch_buf.size() == batch) {
                call_python(batch_buf);
                batch_buf.clear();
            }
        }
        // Flush the tail (if any)
        if (!batch_buf.empty())
            call_python(batch_buf);
    } else {
        // --------------------------- multi‑threaded ---------------------------
        // We split the total range into chunks (one per thread).  Each thread
        // owns its own iterator (or we could share a thread‑safe iterator –
        // the mock iterator is cheap, so we just create one per thread).
        const unsigned int nthreads = std::thread::hardware_concurrency();
        std::atomic<uint64_t> next_start{0};

        std::vector<std::thread> workers;
        workers.reserve(nthreads);

        for (unsigned int t = 0; t < nthreads; ++t) {
            workers.emplace_back([&, t] {
                std::vector<Block> local_batch;
                local_batch.reserve(batch);
                while (true) {
                    uint64_t start = next_start.fetch_add(batch);
                    if (start >= total_blocks) break;
                    uint64_t end = std::min(start + batch, total_blocks);

                    // Simulate a per‑thread iterator over the range [start, end)
                    for (uint64_t i = start; i < end; ++i) {
                        // Build a fake NativeBlock that matches the mock iterator.
                        NativeBlock nb;
                        nb.height = static_cast<uint32_t>(i);
                        nb.hash = "deadbeef" + std::to_string(i);
                        nb.timestamp = std::chrono::seconds(1231006505 + i * 600);
                        nb.tx_count = 200 + (i % 1000);
                        nb.size_bytes = 1'000 + (i % 500);
                        local_batch.emplace_back(nb);
                    }
                    // When the thread finishes its chunk we invoke the callback.
                    // This is still under the GIL, but only once per chunk.
                    call_python(local_batch);
                    local_batch.clear();
                }
            });
        }

        for (auto& thr : workers) thr.join();
    }
}

// -------------------------------------------------------------------------
//  Public entry point that will be bound to Python.
// -------------------------------------------------------------------------
void iter_blocks(py::object py_callback,
                size_t batch = 1,
                bool parallel = false) {
    if (!py::isinstance<py::function>(py_callback))
        throw py::type_error("callback must be a callable");

    // The lambda captures the Python object by value (reference‑counted)
    // and forwards the call to it.  The lambda lives on the C++ side.
    auto cpp_callback = [py_callback](auto&& arg) mutable {
        // ``arg`` is either a Block or a std::vector<Block>.
        // pybind11 will automatically convert it.
        py_callback(arg);
    };

    // The total number of blocks is known by BlockSci – here we hard‑code
    // the mock 800 M value.  In real code you would query the chain object.
    const uint64_t TOTAL_BLOCKS = 800'000'000ULL;

    if (batch == 0)
        throw py::value_error("batch must be >= 1");

    walk_blocks_impl(std::move(cpp_callback), TOTAL_BLOCKS, batch, parallel);
}

// -------------------------------------------------------------------------
//  Helper: a quick way to construct a Block from a height (for the demo).
// -------------------------------------------------------------------------
Block block_from_height(uint64_t height) {
    if (height >= 800'000'000ULL) throw std::out_of_range("height out of range");
    NativeBlock nb;
    nb.height = static_cast<uint32_t>(height);
    nb.hash = "deadbeef" + std::to_string(height);
    nb.timestamp = std::chrono::seconds(1231006505 + height * 600);
    nb.tx_count = 200 + (height % 1000);
    nb.size_bytes = 1'000 + (height % 500);
    return Block(nb);
}

// -------------------------------------------------------------------------
//  pybind11 module definition
// -------------------------------------------------------------------------
PYBIND11_MODULE(blocksci, m) {
    m.doc() = R"pbdoc(
        Python bindings for BlockSci – a high‑performance blockchain analytics engine.
        The hot path is ``iter_blocks`` which walks the native C++ block iterator
        and calls a user‑provided Python callback for each block (or batch of blocks).
    )pbdoc";

    // -----------------------------------------------------------------
    //  Block class – expose read‑only properties.
    // -----------------------------------------------------------------
    py::class_<Block>(m, "Block", R"pbdoc(
        Light‑weight view of a blockchain block.
        Only cheap fields are stored; the object is cheap to copy.
    )pbdoc")
        .def_property_readonly("height", &Block::height,
            "Block height (0‑based).")
        .def_property_readonly("hash", &Block::hash,
            "Hex‑encoded block hash.")
        .def_property_readonly("timestamp", &Block::timestamp,
            "Block timestamp as a ``datetime.datetime`` (UTC).")
        .def_property_readonly("tx_count", &Block::tx_count,
            "Number of transactions in the block.")
        .def_property_readonly("size", &Block::size,
            "Serialized block size in bytes.")
        .def_static("from_height", &block_from_height,
            py::arg("height"),
            "Construct a ``Block`` object from a block height (for testing).");

    // -----------------------------------------------------------------
    //  iter_blocks – the hot entry point.
    // -----------------------------------------------------------------
    m.def("iter_blocks",
          &iter_blocks,
          py::arg("callback"),
          py::arg("batch") = 1,
          py::arg("parallel") = false,
          R"pbdoc(
            Walk the whole blockchain and invoke ``callback`` for each block.

            Parameters
            ----------
            callback : Callable[[Block] | Callable[[list[Block]]], Any]
                Function that will be called for each block (or each batch of
                blocks).  It receives either a ``Block`` instance (``batch==1``)
                or a ``list[Block]`` when ``batch>1``.
            batch : int, default 1
                Number of blocks to pack into a single list before invoking the
                callback.  ``1`` gives the most “row‑wise” feel; larger values
                reduce Python call overhead.
            parallel : bool, default False
                If True, the walk is performed in parallel across CPU cores.
                The callback is still executed under the GIL, once per thread,
                so the Python code must be thread‑safe.

            Notes
            -----
            The GIL is released for the entire walk; only the user callback
            runs with the GIL held.  This makes the iteration essentially as
            fast as pure C++ while still giving Python the flexibility to
            execute custom logic per block.
          )pbdoc");
}
```

### How the code works

| Piece | What it does | Why it matters for performance |
|------|--------------|--------------------------------|
| **`NativeBlockIterator`** | Mock of BlockSci’s native iterator (in real code you’ll include the real one). | Keeps the hot loop in C++. |
| **`walk_blocks_impl`** | The tight loop that pulls native blocks, builds a cheap `Block` wrapper, and batches them. | No Python interaction until a batch is ready – the hot path stays C++. |
| **`py::gil_scoped_acquire`** | Acquires the Python GIL *only* during the callback invocation. | GIL is released for the whole walk, so other Python threads can run. |
| **`batch`** | Packs `batch` blocks into a `std::vector<Block>` and passes a Python list. | Reduces the number of Python calls by a factor of `batch`. |
| **`parallel`** | Splits the work across OpenMP‑like threads (implemented with `std::thread`). | Gives an extra speed‑up on multi‑core machines when the callback is thread‑safe. |
| **`py::stl.h` + `py::chrono.h`** | Automatic conversion of `std::vector<Block>` → Python list and of `std::chrono::system_clock::time_point` → `datetime.datetime`. | No manual boilerplate – the API stays clean. |

