## 3. Minimal `setup.py` to build the extension

```python
# setup.py --------------------------------------------------------------
# This is a tiny build script – replace the include paths with the real
# BlockSci headers when you integrate it for real.
# --------------------------------------------------------------
from setuptools import setup, Extension
import sys, os, pathlib

import pybind11

# Helper to locate the pybind11 include directory
include_dirs = [
    pybind11.get_include(),
    # Add the real BlockSci include path here, e.g.:
    # "/usr/local/include/blocksci",
]

ext_modules = [
    Extension(
        "blocksci",
        ["blocksci_bindings.cpp"],
        include_dirs=include_dirs,
        language="c++",
        extra_compile_args=["-O3", "-march=native", "-std=c++17"],
    ),
]

setup(
    name="blocksci",
    version="0.1.0",
    author="Your Name",
    description="Python bindings for BlockSci – per‑block callbacks",
    ext_modules=ext_modules,
    zip_safe=False,
)
```

Run the usual build command:

```bash
python -m pip install .
```

